+/** A condition accepted by conditional option helpers. */
+export type OptionCondition = string | OptionDependency;
+
+function normalizeDependency(condition: OptionCondition): OptionDependency {
+  return typeof condition === "string" ? { option: condition } : condition;
+}
+
+function conditionalOptionImpl<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T> | undefined,
+  required: boolean | undefined,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = Array.isArray(flagSpec) ? flagSpec : [flagSpec];
+  const dependsOn = {
+    ...normalizeDependency(condition),
+    ...(required === undefined ? {} : { required }),
+  };
+  if (valueParser == null) return option(...names, { dependsOn });
+  return option(...names, valueParser, { dependsOn });
+}
+
+/**
+ * Creates an option that is required when a condition is satisfied.
+ * @since 0.10.0
+ */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, true);
+}
+
+/**
+ * Creates an option that is visible only when a condition is satisfied.
