+function findOptionTerm(usage: Usage): Extract<UsageTerm, { type: "option" }> | undefined {
+  for (const term of usage) {
+    if (term.type === "option") return term;
+    if (term.type === "optional" || term.type === "multiple") {
+      const option = findOptionTerm(term.terms);
+      if (option) return option;
+    }
+  }
+  return undefined;
+}
+
+function unwrapOptionState(state: unknown): { readonly present: boolean; readonly value: unknown } {
+  if (Array.isArray(state)) return state.length === 0
+    ? { present: false, value: undefined }
+    : unwrapOptionState(state[0]);
+  if (state != null && typeof state === "object") {
+    if ("result" in state) return unwrapOptionState(
+      (state as { readonly result: unknown }).result,
+    );
+    if ("preliminaryResult" in state) return unwrapOptionState(
+      (state as { readonly preliminaryResult: unknown }).preliminaryResult,
+    );
+    if ("success" in state) {
+      const result = state as { readonly success: unknown; readonly value?: unknown };
+      return result.success === true
+        ? { present: true, value: result.value }
+        : { present: false, value: undefined };
+    }
+  }
+  return { present: state !== undefined, value: state };
+}
+
+function dependencySatisfied(
+  dependency: OptionDependency,
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+  state: Record<string | symbol, unknown>,
+): boolean {
+  const evaluate = (condition: OptionDependencyCondition): boolean => {
+    const pair = parserPairs.find(([key, parser]) =>
+      key === condition.option || findOptionTerm(parser.usage)?.names.includes(condition.option as never)
+    );
+    if (!pair) return false;
+    const optionState = unwrapOptionState(state[pair[0]]);
