+    option: dependency.option,
+    ...(Object.hasOwn(dependency, "value") ? { value: dependency.value } : {}),
+  };
+  const allOf = dependency.allOf ?? (single ? [single] : []);
+  return allOf.every(evaluate) && (dependency.anyOf?.some(evaluate) ?? true);
+}
